openai.api_key = "YOUR_API_KEY"

def chatbot():
    while True:
        # Get user input
        user_input = input("User: ")

        # Concatenate system instructions with user input
        prompt = f"User said: {user_input}\nSystem response: "

        # Send to GPT model and get response
        response = openai.Completion.create(
            engine="text-davinci-002",
            prompt=prompt,
            max_tokens=2048,
            n=1,
            stop=None,
            temperature=0.5,
            top_p=1,
            frequency_penalty=0,
            presence_penalty=0
        )

